def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60 + np.sqrt(cap) * 33 + np.log(cap + 0.5) * 20
        mod_factor = int(cap * 1000)
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 12:
                base_priority += 120 * np.cbrt(cap) + 40 * np.cos(cap * 1.8)
            else:
                base_priority -= 45 * usage
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 25 / i
            if mod_factor % 7 == 0:
                base_priority += 150
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.4 + 0.4)) * 30 / j
            if int(cap * 2.7) % 4 == 1:
                base_priority += 50 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 6 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.3:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 2.2
            for m in range(1, 17):
                pwr = usage ** m
                if pwr < 0.65:
                    fluctuation += pwr * 20 / m
                    if m % 2 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 2)
                    if m == 14 and usage > 2.75:
                        fluctuation += 18
            if cap % 2.7 < 0.4:
                base_priority += 40 * np.cos(cap * 3.5)
        elif 1 < usage <= 2:
            base_priority += 750 * (usage - 1) ** 3.5
            for n in range(1, 20):
                cur_pow = usage ** n
                if cur_pow < 0.7:
                    fluctuation += cur_pow * 30 / n
                    if n % 4 == 3:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - cur_pow) * 15 / (n + 1)
                    if n == 17 and usage > 1.85:
                        fluctuation += 22
            if cap % 1.9 < 0.25:
                base_priority += 33 * np.cos(cap * 2.4)
        elif 0.7 < usage <= 1:
            base_priority += 180 * (1 - usage)
            for o in range(1, 14):
                pw = usage ** o
                fluctuation += (np.tanh(pw * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 310
            elif cap < 0.75:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4.7) * 25
        elif 0.3 < usage <= 0.7:
            base_priority += 320 * (1 - usage) ** 1.8
            for p in range(1, 22):
                pw = usage**p
                fluctuation += (np.sin(pw * np.pi / 5) - 0.3) * 14 / p
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.8:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 5.7) * 35
        else:
            base_priority += 400 * (1 - usage) ** 2.5
            for q in range(1, 25):
                pw = usage ** q
                fluctuation += (np.sin(pw * np.pi / 8) - 0.2) * 16 / q
                if usage < 0.01 * q:
                    fluctuation -= 18 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 380
            elif cap < 0.85:
                base_priority += np.log1p(cap * 35) * 55
            else:
                base_priority += (cap % 6.5) * 40
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 0.95:
            priority += 45
            if usage > 0.9:
                priority += 65
            elif usage < 0.22:
                priority -= 35
            for s in range(1, 7):
                if mod_factor % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 45
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.94:
                priority += 95
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 40
        prox = 0
        if mod_factor % 23 == 0:
            prox += 20
        if int(cap * 850) % 19 == 0:
            prox -= 15
        if int(cap * 200) % 11 == 0:
            prox += 18
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                prox += 25 / w
            elif diff < 0.04:
                prox += 12 / w
            else:
                prox -= 6 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                prox += x * 6
            elif mod_chk == 5:
                prox -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                prox += 14 * y
            elif mod_chk == 4:
                prox -= 10 * y
        priority += prox
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 14
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1.2 < 0.08:
                priority += 50
            if (mod_factor % 29 == 0) and (usage > 0.75):
                priority += 80
            for bb in range(1, 8):
                if (int(cap * 720) % (bb + 12) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
